codeComparison.new:
.container { display: flex; gap: 20px; }
.box { flex: 1; } /* Equal width columns! */

.vertical { flex-direction: column; }

.container {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
}

.grid {
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
}
/* Automatically adjusts columns based on screen width! */

.modal-overlay {
  position: fixed;
  top: 0; left: 0;
  width: 100%; height: 100%;
  background: rgba(0,0,0,0.8);
  z-index: 1000;
  display: flex;
  justify-content: center;
  align-items: center;
}
.modal-content {
  background: white;
  padding: 40px;
  border-radius: 12px;
}

codeComparison.old:
/* Images are inline by default - gap below! */
.image-container img {
  max-width: 100%;
}

codeComparison.new:
/* Fix: make image block to remove gap */
.image-container img {
  max-width: 100%;
  display: block;
}

/* Buttons side by side with inline-block */
.btn {
  display: inline-block;
  background-color: #007bff;
  color: white;
  padding: 12px 24px;
  border: none;
  border-radius: 4px;
  margin-right: 10px;
}

codeComparison.old:
/* Desktop only — menu always visible */
.nav-links {
  display: flex;
  list-style: none;
}

codeComparison.new:
/* Mobile: slide-in menu */
@media (max-width: 768px) {
  .menu-toggle {
    display: block;
  }

  .nav-links {
    position: fixed;
    top: 70px;
    right: -100%;
    flex-direction: column;
    background-color: #333;
    width: 250px;
    height: calc(100vh - 70px);
    transition: right 0.3s ease;
  }

  .nav-links.active {
    right: 0;
  }
}
